import{_ as i,c as a,o as n,a0 as t}from"./chunks/framework.zS86-xgI.js";const k=JSON.parse('{"title":"一、cuda的安装与使用","description":"","frontmatter":{},"headers":[],"relativePath":"markdown/aitool/other/cuda/01.md","filePath":"markdown/aitool/other/cuda/01.md"}'),e={name:"markdown/aitool/other/cuda/01.md"};function l(o,s,d,p,h,r){return n(),a("div",null,s[0]||(s[0]=[t(`<h1 id="一、cuda的安装与使用" tabindex="-1">一、cuda的安装与使用 <a class="header-anchor" href="#一、cuda的安装与使用" aria-label="Permalink to &quot;一、cuda的安装与使用&quot;">​</a></h1><h2 id="_1-1-安装cuda-以主流方式为例" tabindex="-1">1.1 安装CUDA（以主流方式为例） <a class="header-anchor" href="#_1-1-安装cuda-以主流方式为例" aria-label="Permalink to &quot;1.1 安装CUDA（以主流方式为例）&quot;">​</a></h2><p>CUDA的安装方式有多种，您可以根据自己的操作系统和使用习惯选择最合适的一种。</p><h3 id="_1-1-1-windows系统" tabindex="-1">1.1.1 <strong>Windows系统</strong> <a class="header-anchor" href="#_1-1-1-windows系统" aria-label="Permalink to &quot;1.1.1 **Windows系统**&quot;">​</a></h3><p>在Windows上，最直接的方式是使用NVIDIA提供的<strong>本地或网络安装包</strong>。</p><ol><li><p><strong>下载</strong>：访问 <a href="https://developer.nvidia.com/cuda-downloads" target="_blank" rel="noreferrer">CUDA Toolkit下载页面</a>，选择您的Windows版本和安装包类型。本地安装包（Local）较大但可离线安装，网络安装包（Network）较小但需在安装时下载所需组件。</p></li><li><p><strong>安装</strong>：双击下载的安装包，按照屏幕提示操作即可。安装过程会包含CUDA驱动（如果未安装或版本较旧）、CUDA runtime库、开发工具（如NVCC编译器）等核心组件。</p></li><li><p><strong>其他方式</strong>：</p><ul><li><strong>Conda</strong>：如果您是Python用户，可以使用Conda进行安装，它能更好地管理环境依赖：<code>conda install cuda -c nvidia</code>。</li><li><strong>Pip Wheels</strong>：NVIDIA也提供了Python wheels包，方便在Python环境中直接安装CUDA runtime：<code>py -m pip install nvidia-cuda-runtime-cu12</code>。</li></ul></li></ol><h3 id="_1-1-2-linux系统" tabindex="-1">1.1.2 <strong>Linux系统</strong> <a class="header-anchor" href="#_1-1-2-linux系统" aria-label="Permalink to &quot;1.1.2 **Linux系统**&quot;">​</a></h3><p>Linux下的安装方式更为灵活，主要有以下几种：</p><ol><li><strong>包管理器安装（推荐）</strong>： <ul><li><p>这是最推荐的方式，因为它会自动处理依赖关系，便于后续的更新和卸载。</p></li><li><p>对于<strong>Ubuntu/Debian</strong>系统，可以使用<code>apt</code>命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nvidia-cuda-toolkit</span></span></code></pre></div></li><li><p>对于<strong>Red Hat/CentOS</strong>系统，可以使用<code>yum</code>或<code>dnf</code>。首先需要添加NVIDIA的官方仓库。</p></li></ul></li><li><strong>Runfile安装</strong>： <ul><li>这种方式提供了一个独立的、与发行版无关的安装包，适合需要高度定制化安装的场景。</li><li>首先从官网下载 <code>.run</code> 文件。然后，执行以下命令开始安装：<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cuda_</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">versio</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">_linux.run</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./cuda_</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">versio</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">_linux.run</span></span></code></pre></div>需要注意的是，在安装过程中，如果您的系统<strong>已经安装了NVIDIA显卡驱动，务必取消勾选<code>Driver</code>选项</strong>，以避免驱动冲突。</li></ul></li></ol><h2 id="_1-2-验证与查看cuda安装" tabindex="-1">1.2 验证与查看CUDA安装 <a class="header-anchor" href="#_1-2-验证与查看cuda安装" aria-label="Permalink to &quot;1.2 验证与查看CUDA安装&quot;">​</a></h2><p>安装完成后，需要通过几个简单的命令来确认CUDA是否安装成功以及版本信息。</p><ol><li><p><strong>查看CUDA编译器版本</strong>： 在命令行中输入 <code>nvcc --version</code> 或 <code>nvcc -V</code>。如果安装成功，您将看到CUDA编译器的版本号，这代表了您安装的CUDA Toolkit的版本。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nvcc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div></li><li><p><strong>查看NVIDIA驱动信息和运行时CUDA版本</strong>： 在命令行中输入 <code>nvidia-smi</code>。这个命令会列出您GPU的详细信息、NVIDIA驱动版本，以及<strong>Driver API支持的CUDA版本</strong>。如下图所示，右上角的&quot;CUDA Version&quot;表示您的驱动最高可以支持到这个版本的CUDA。</p></li><li><p><strong>运行官方示例程序（可选，强烈推荐）</strong>： 这是验证CUDA功能完整性的最佳方法。您可以下载NVIDIA提供的CUDA示例代码，编译并运行<code>deviceQuery</code>和<code>bandwidthTest</code>这两个小程序。</p><ul><li>在<strong>Windows</strong>下，您需要找到CUDA Samples目录（如 <code>C:\\ProgramData\\NVIDIA Corporation\\CUDA Samples</code>），打开其中的Visual Studio解决方案文件（如 <code>Samples.sln</code>），在Visual Studio中编译整个解决方案。然后，在命令行中进入到编译输出的目录（如 <code>\\bin\\win64\\Release</code>），分别运行 <code>deviceQuery.exe</code> 和 <code>bandwidthTest.exe</code>。</li><li>在<strong>Linux</strong>下，您可以通过以下命令操作：<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 进入示例程序编译目录（请根据您的CUDA安装路径调整）</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/local/cuda/extras/demo_suite/</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 运行deviceQuery</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./deviceQuery</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 运行bandwidthTest</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./bandwidthTest</span></span></code></pre></div></li></ul><p>如果这两个程序的运行结果最后都显示 <strong><code>Result = PASS</code></strong>，那么恭喜您，CUDA已经成功安装并可正常使用。</p></li></ol>`,12)]))}const g=i(e,[["render",l]]);export{k as __pageData,g as default};
